1	// User input processing and drag-to-swap mechanics
2	
3	import {
4	    getTileValue,
5	    createTile,
6	    createJokerTile,
7	    isBlocked,
8	    isBlockedWithLife,
9	    isBlockedMovable,
10	    isBlockedWithMergeCount,
11	    isRectangularBlocked,
12	    isJoker,
13	    isTileFreeSwapTile,
14	    isTileStickyFreeSwapTile,
15	    isTileFreeSwapHorizontalTile,
16	    isTileFreeSwapVerticalTile,
17	    isTileHammerTile,
18	    isTileHalverTile,
19	    isTileTeleportTile,
20	    isWildTeleportTile,
21	    getDisplayValue,
22	    findBestJokerValue,
23	    getUniqueTileValues,
24	} from "./tile-helpers.js";
25	import { track } from "./tracker.js";
26	import { getMatchTilesForSwap } from "./hint-system.js";
27	import {
28	    isTutorialActive,
29	    isValidTutorialSwap,
30	    advanceTutorialStep,
31	    canDragTileInTutorial,
32	    isTutorialTapStep,
33	    isValidTutorialTap,
34	    isTutorialPowerUpStep,
35	    isValidTutorialPowerUp,
36	    isValidTutorialPowerUpTarget,
37	    updateTutorialUI,
38	} from "./tutorial.js";
39	
40	export function setupEventListeners(game) {
41	    const gameBoard = document.getElementById("gameBoard");
42	
43	    // Touch events for mobile
44	    gameBoard.addEventListener("touchstart", handleTouchStart.bind(game), { passive: false });
45	    gameBoard.addEventListener("touchmove", handleTouchMove.bind(game), { passive: false });
46	    gameBoard.addEventListener("touchend", handleTouchEnd.bind(game), { passive: false });
47	
48	    // Mouse events for desktop
49	    gameBoard.addEventListener("mousedown", handleMouseDown.bind(game));
50	    gameBoard.addEventListener("mousemove", handleMouseMove.bind(game));
51	    gameBoard.addEventListener("mouseup", handleMouseUp.bind(game));
52	    gameBoard.addEventListener("mouseleave", handleMouseUp.bind(game));
53	}
54	
55	function handleTouchStart(e) {
56	    e.preventDefault();
57	    const touch = e.touches[0];
58	    startDrag(this, touch.clientX, touch.clientY);
59	}
60	
61	function handleTouchMove(e) {
62	    e.preventDefault();
63	    const touch = e.touches[0];
64	    updateDrag(this, touch.clientX, touch.clientY);
65	}
66	
67	function handleTouchEnd(e) {
68	    e.preventDefault();
69	    endDrag(this);
70	}
71	
72	function handleMouseDown(e) {
73	    startDrag(this, e.clientX, e.clientY);
74	}
75	
76	function handleMouseMove(e) {
77	    updateDrag(this, e.clientX, e.clientY);
78	}
79	
80	function handleMouseUp() {
81	    endDrag(this);
82	}
83	
84	function startDrag(game, x, y) {
85	    if (!game.gameActive) return;
86	
87	    // Clear hint on user interaction (don't start timer until drag ends)
88	    game.clearHint();
89	    game.clearHintTimer();
90	
91	    const element = document.elementFromPoint(x, y);
92	    if (element && element.classList.contains("gem")) {
93	        const row = parseInt(element.dataset.row);
94	        const col = parseInt(element.dataset.col);
95	        const tile = game.board[row][col];
96	
97	        // Block dragging tiles during tutorial if not part of the tutorial step
98	        if (isTutorialActive(game) && !canDragTileInTutorial(game, row, col)) {
99	            return;
100	        }
101	
102	        // Handle power-ups (but not during animations)
103	        if (game.activePowerUp) {
104	            // Prevent power-up usage during animations
105	            if (game.animating) return;
106	
107	            // Check tutorial validation for power-up usage
108	            if (isTutorialActive(game) && isTutorialPowerUpStep(game)) {
109	                // Only allow clicking on the specified tutorial target
110	                if (!isValidTutorialPowerUpTarget(game, row, col)) {
111	                    return; // Block usage on wrong tile
112	                }
113	            }
114	
115	            const handled = game.handlePowerUpAction(row, col, element);
116	            if (handled !== false) {
117	                // If power-up was used successfully, advance tutorial
118	                if (isTutorialActive(game) && isTutorialPowerUpStep(game)) {
119	                    advanceTutorialStep(game);
120	                }
121	                return;
122	            }
123	            // If handlePowerUpAction returns false (swap case), continue with normal drag
124	        }
125	
126	        if (isBlockedWithLife(tile) || isBlockedMovable(tile) || isRectangularBlocked(tile)) {
127	            return;
128	        }
129	        if (isBlocked(tile) && game.activePowerUp !== "swap") {
130	            return;
131	        }
132	
133	        // Normal drag behavior (including joker)
134	        game.selectedGem = {
135	            element: element,
136	            row: row,
137	            col: col,
138	            tile: tile, // Store tile to detect joker taps later
139	        };
140	        game.isDragging = true;
141	        game.dragStartPos = { x, y };
142	        element.classList.add("dragging");
143	        showValidSwapTargets(game, row, col);
144	    }
145	}
146	
147	function updateDrag(game, x, y) {
148	    if (!game.isDragging || !game.selectedGem) return;
149	
150	    const element = document.elementFromPoint(x, y);
151	    if (element && element.classList.contains("gem")) {
152	        // If user drags back to the original tile, cancel the preview
153	        if (element === game.selectedGem.element) {
154	            clearDragPreviews();
155	            return;
156	        }
157	
158	        const targetRow = parseInt(element.dataset.row);
159	        const targetCol = parseInt(element.dataset.col);
160	
161	        // Check if gems are adjacent or allowed by extended free swap rules
162	        if (canPreviewSwap(game, game.selectedGem.row, game.selectedGem.col, targetRow, targetCol)) {
163	            previewSwap(game, game.selectedGem.row, game.selectedGem.col, targetRow, targetCol);
164	        }
165	    }
166	}
167	
168	function endDrag(game) {
169	    if (!game.isDragging || !game.selectedGem) return;
170	
171	    const previewGems = document.querySelectorAll(".gem.preview");
172	
173	    if (previewGems.length > 0) {
174	        // User dragged to swap
175	        const targetGem = Array.from(previewGems).find((g) => g !== game.selectedGem.element);
176	        if (targetGem) {
177	            const targetRow = parseInt(targetGem.dataset.row);
178	            const targetCol = parseInt(targetGem.dataset.col);
179	            trySwap(game, game.selectedGem.row, game.selectedGem.col, targetRow, targetCol);
180	        }
181	    } else if (isJoker(game.selectedGem.tile) && !game.activePowerUp) {
182	        // User tapped on joker without dragging - try to activate it
183	        // Only activate if not in power-up mode
184	
185	        // Check if this is a valid tutorial tap
186	        if (isTutorialActive(game) && isTutorialTapStep(game)) {
187	            if (isValidTutorialTap(game, game.selectedGem.row, game.selectedGem.col)) {
188	                activateJokerByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
189	                // Note: Tutorial progression is handled in the joker activation callback
190	            }
191	        } else if (!isTutorialActive(game)) {
192	            activateJokerByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
193	        }
194	    } else if (isTileHammerTile(game.selectedGem.tile) && !game.activePowerUp) {
195	        // User tapped on hammer tile without dragging - activate it
196	        // Only activate if not in power-up mode
197	        activateHammerTileByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
198	    } else if (isTileHalverTile(game.selectedGem.tile) && !game.activePowerUp) {
199	        // User tapped on halver tile without dragging - activate it
200	        // Only activate if not in power-up mode
201	        activateHalverTileByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
202	    }
203	
204	    // Clean up
205	    document.querySelectorAll(".gem").forEach((gem) => {
206	        gem.classList.remove("dragging", "preview", "merge-preview", "unblock-preview", "swap-dimmed");
207	    });
208	
209	    // Reset hint timer after user interaction completes
210	    game.resetHintTimer();
211	
212	    game.selectedGem = null;
213	    game.isDragging = false;
214	    game.dragStartPos = null;
215	}
216	
217	function activateJokerByTap(game, row, col, element) {
218	    // Activate joker when tapped
219	    const bestValue = findBestJokerValue(game, row, col);
220	
221	    if (bestValue !== null) {
222	        // Transform and animate
223	        game.animating = true;
224	        element.style.transform = "scale(1.2)";
225	        element.textContent = getDisplayValue(bestValue);
226	        element.className = `gem tile-${bestValue}`;
227	
228	        setTimeout(() => {
229	            element.style.transform = "scale(1)";
230	            game.board[row][col] = createTile(bestValue); // Update board
231	
232	            // Set lastSwapPosition to the joker position so other jokers connected to this one can activate
233	            game.lastSwapPosition = { row, col, movedFrom: { row, col } };
234	
235	            game.renderBoard(); // Re-render to show the updated tile
236	
237	            // Progress tutorial if this was a tap-only tutorial step
238	            if (isTutorialActive(game) && isTutorialTapStep(game)) {
239	                advanceTutorialStep(game);
240	            }
241	
242	            setTimeout(() => {
243	                game.isUserSwap = true; // Treat tap as user action
244	                game.processMatches();
245	            }, 200);
246	        }, 300);
247	    } else {
248	        // No valid match found - indicate to user with a shake animation
249	        element.style.animation = "shake 0.3s";
250	        setTimeout(() => {
251	            element.style.animation = "";
252	        }, 300);
253	    }
254	}
255	
256	function activateHammerTileByTap(game, row, col, element) {
257	    // Activate hammer tile when tapped - removes the tile
258	
259	    // Animate removal
260	    game.animating = true;
261	    element.style.transform = "scale(0.5)";
262	    element.style.opacity = "0";
263	
264	    setTimeout(() => {
265	        // Remove the tile from the board
266	        game.board[row][col] = null;
267	        game.renderBoard();
268	
269	        setTimeout(() => {
270	            // Drop tiles and process matches
271	            game.isUserSwap = true;
272	            game.dropGems();
273	        }, 200);
274	    }, 300);
275	}
276	
277	function activateHalverTileByTap(game, row, col, element) {
278	    // Activate halver tile when tapped - halves the tile's value
279	    const currentValue = getTileValue(game.board[row][col]);
280	
281	    // Can only halve if value is greater than 1
282	    if (currentValue <= 1) {
283	        // Cannot halve further - show shake animation
284	        element.style.animation = "shake 0.3s";
285	        setTimeout(() => {
286	            element.style.animation = "";
287	        }, 300);
288	        return;
289	    }
290	
291	    // Calculate new value (halve it)
292	    const newValue = currentValue - 1; // Internal value decreased by 1 (which halves the display value)
293	
294	    // Animate the change
295	    game.animating = true;
296	    element.style.transform = "scale(1.2)";
297	
298	    setTimeout(() => {
299	        element.style.transform = "scale(1)";
300	        // Update the tile to regular tile with new value (no longer a halver tile)
301	        game.board[row][col] = createTile(newValue);
302	        game.renderBoard();
303	
304	        setTimeout(() => {
305	            // Process any matches that may have been created
306	            game.isUserSwap = true;
307	            game.processMatches();
308	        }, 200);
309	    }, 300);
310	}
311	
312	function areAdjacent(row1, col1, row2, col2) {
313	    const rowDiff = Math.abs(row1 - row2);
314	    const colDiff = Math.abs(col1 - col2);
315	    return (rowDiff === 1 && colDiff === 0) || (rowDiff === 0 && colDiff === 1);
316	}
317	
318	function clearDragPreviews() {
319	    document.querySelectorAll(".gem.preview").forEach((gem) => {
320	        gem.classList.remove("preview");
321	    });
322	    document.querySelectorAll(".gem.merge-preview").forEach((gem) => {
323	        gem.classList.remove("merge-preview");
324	    });
325	    document.querySelectorAll(".gem.unblock-preview").forEach((gem) => {
326	        gem.classList.remove("unblock-preview");
327	    });
328	}
329	
330	function showValidSwapTargets(game, row, col) {
331	    if (!game.showSwapTargets) return;
332	    const gems = document.querySelectorAll(".gem");
333	    for (const gem of gems) {
334	        const r = parseInt(gem.dataset.row);
335	        const c = parseInt(gem.dataset.col);
336	        if (isNaN(r) || isNaN(c)) continue;
337	        if (r === row && c === col) continue;
338	        if (!canPreviewSwap(game, row, col, r, c)) {
339	            gem.classList.add("swap-dimmed");
340	        }
341	    }
342	}
343	
344	function canPreviewSwap(game, row1, col1, row2, col2) {
345	    if (areAdjacent(row1, col1, row2, col2)) {
346	        return true;
347	    }
348	
349	    if (game.activePowerUp === "teleport") {
350	        return true;
351	    }
352	
353	    if (isTeleportSwapAllowed(game, row1, col1, row2, col2)) {
354	        return true;
355	    }
356	
357	    return isExtendedFreeSwapAllowed(game, row1, col1, row2, col2);
358	}
359	
360	function isTeleportSwapAllowed(game, row1, col1, row2, col2) {
361	    const tile1 = game.board[row1][col1];
362	    const tile2 = game.board[row2][col2];
363	
364	    // Can't teleport to/from blocked tiles
365	    if (isBlocked(tile1) || isBlocked(tile2) || isBlockedWithLife(tile1) || isBlockedWithLife(tile2)) {
366	        return false;
367	    }
368	
369	    const isTeleport1 = (isTileTeleportTile(tile1) || isWildTeleportTile(tile1)) && !tile1.hasBeenSwapped;
370	
371	    return isTeleport1;
372	}
373	
374	function isExtendedFreeSwapAllowed(game, row1, col1, row2, col2) {
375	    if (game.extendedFreeSwap !== true) {
376	        return false;
377	    }
378	
379	    const isHorizontalSwap = row1 === row2;
380	    const isVerticalSwap = col1 === col2;
381	
382	    if (!isHorizontalSwap && !isVerticalSwap) {
383	        return false;
384	    }
385	
386	    const tile1 = game.board[row1][col1];
387	
388	    const isFreeSwap1 = (isTileFreeSwapTile(tile1) || isTileStickyFreeSwapTile(tile1)) && !tile1.hasBeenSwapped;
389	
390	    const isDirectionalFreeSwap1 =
391	        !tile1.hasBeenSwapped &&
392	        ((isTileFreeSwapHorizontalTile(tile1) && isHorizontalSwap) ||
393	            (isTileFreeSwapVerticalTile(tile1) && isVerticalSwap));
394	
395	    return isFreeSwap1 || isDirectionalFreeSwap1;
396	}
397	
398	function previewSwap(game, row1, col1, row2, col2) {
399	    // Clear previous previews
400	    clearDragPreviews();
401	
402	    // Add preview to both gems
403	    const gem1 = document.querySelector(`[data-row="${row1}"][data-col="${col1}"]`);
404	    const gem2 = document.querySelector(`[data-row="${row2}"][data-col="${col2}"]`);
405	
406	    if (gem1 && gem2) {
407	        gem1.classList.add("preview");
408	        gem2.classList.add("preview");
409	
410	        // Get tiles that would merge if swap completes
411	        const matchTiles = getMatchTilesForSwap(game, row1, col1, row2, col2);
412	
413	        // Highlight merge tiles
414	        for (const tile of matchTiles) {
415	            const matchGem = document.querySelector(`[data-row="${tile.row}"][data-col="${tile.col}"]`);
416	            matchGem?.classList.add("merge-preview");
417	        }
418	
419	        // Highlight blocked tiles that would be unblocked
420	        // matchTiles are in PRE-SWAP coords, convert to POST-SWAP for adjacency check
421	        const blockedToUnblock = getBlockedTilesForMatch(game, matchTiles, row1, col1, row2, col2);
422	        for (const pos of blockedToUnblock) {
423	            const blockedGem = document.querySelector(`[data-row="${pos.row}"][data-col="${pos.col}"]`);
424	            blockedGem?.classList.add("unblock-preview");
425	        }
426	    }
427	}
428	
429	function getBlockedTilesForMatch(game, matchTiles, row1, col1, row2, col2) {
430	    const blockedSet = new Set();
431	    const result = [];
432	
433	    for (const tile of matchTiles) {
434	        // Convert pre-swap to post-swap coordinates
435	        let checkRow = tile.row;
436	        let checkCol = tile.col;
437	        if (tile.row === row1 && tile.col === col1) {
438	            checkRow = row2;
439	            checkCol = col2;
440	        } else if (tile.row === row2 && tile.col === col2) {
441	            checkRow = row1;
442	            checkCol = col1;
443	        }
444	
445	        const adjacentPositions = [
446	            { row: checkRow - 1, col: checkCol },
447	            { row: checkRow + 1, col: checkCol },
448	            { row: checkRow, col: checkCol - 1 },
449	            { row: checkRow, col: checkCol + 1 },
450	        ];
451	
452	        for (const pos of adjacentPositions) {
453	            if (pos.row >= 0 && pos.row < game.boardHeight && pos.col >= 0 && pos.col < game.boardWidth) {
454	                const key = `${pos.row}_${pos.col}`;
455	                if (!blockedSet.has(key)) {
456	                    const adjacentTile = game.board[pos.row][pos.col];
457	                    if (
458	                        isBlocked(adjacentTile) ||
459	                        isBlockedWithLife(adjacentTile) ||
460	                        isBlockedMovable(adjacentTile) ||
461	                        isBlockedWithMergeCount(adjacentTile)
462	                    ) {
463	                        blockedSet.add(key);
464	                        result.push(pos);
465	                    }
466	                }
467	            }
468	        }
469	    }
470	
471	    return result;
472	}
473	
474	/**
475	 * Execute the board-level swap logic (pure: no DOM, no animation).
476	 * Mutates game.board and game state flags.
477	 * @returns {{ valid: boolean, hasMatch: boolean, hasFreeSwap: boolean, hasTeleport: boolean,
478	 *             isSwapPowerUp: boolean, isTeleportPowerUp: boolean, allowNonMatchingSwap: boolean }}
479	 *   An invalid or disallowed swap is indicated by `valid: false`.
480	 */
481	export function executeSwap(game, row1, col1, row2, col2) {
482	    const tile1 = game.board[row1][col1];
483	
484	    const isHorizontalSwap = row1 === row2;
485	    const isVerticalSwap = col1 === col2;
486	
487	    const isFreeSwap1 = (isTileFreeSwapTile(tile1) || isTileStickyFreeSwapTile(tile1)) && !tile1.hasBeenSwapped;
488	    const isDirectionalFreeSwap1 =
489	        !tile1.hasBeenSwapped &&
490	        ((isTileFreeSwapHorizontalTile(tile1) && isHorizontalSwap) ||
491	            (isTileFreeSwapVerticalTile(tile1) && isVerticalSwap));
492	    const hasFreeSwap = isFreeSwap1 || isDirectionalFreeSwap1;
493	    const hasTeleport = (isTileTeleportTile(tile1) || isWildTeleportTile(tile1)) && !tile1.hasBeenSwapped;
494	    const isSwapPowerUp = game.activePowerUp === "swap";
495	    const isTeleportPowerUp = game.activePowerUp === "teleport";
496	    const allowNonMatchingSwap = game.allowNonMatchingSwaps === true;
497	
498	    // Perform the board swap
499	    const temp = game.board[row1][col1];
500	    game.board[row1][col1] = game.board[row2][col2];
501	    game.board[row2][col2] = temp;
502	
503	    game.lastSwapPosition = { row: row2, col: col2, movedFrom: { row: row1, col: col1 } };
504	    game.isUserSwap = true;
505	
506	    const hasMatch = game.hasMatchesForSwap(row1, col1, row2, col2);
507	
508	    if (hasMatch || isSwapPowerUp || isTeleportPowerUp || hasFreeSwap || hasTeleport || allowNonMatchingSwap) {
509	        // Count the move
510	        if (!isSwapPowerUp && !isTeleportPowerUp && !hasFreeSwap && !hasTeleport) {
511	            game.movesUsed++;
512	        }
513	
514	        game.shouldDecrementCursedTimers = true;
515	        game.cursedTileCreatedThisTurn = {};
516	
517	        // Mark free swap tile as used (tile1 is now at row2/col2 after swap)
518	        if (hasFreeSwap) {
519	            game.board[row2][col2].hasBeenSwapped = true;
520	        }
521	        if (hasTeleport) {
522	            game.board[row2][col2].hasBeenSwapped = true;
523	        }
524	
525	        return {
526	            valid: true,
527	            hasMatch,
528	            hasFreeSwap,
529	            hasTeleport,
530	            isSwapPowerUp,
531	            isTeleportPowerUp,
532	            allowNonMatchingSwap,
533	        };
534	    } else {
535	        // Revert the swap
536	        game.board[row2][col2] = game.board[row1][col1];
537	        game.board[row1][col1] = temp;
538	        game.lastSwapPosition = null;
539	        game.isUserSwap = false;
540	        return {
541	            valid: false,
542	            hasMatch: false,
543	            hasFreeSwap,
544	            hasTeleport,
545	            isSwapPowerUp,
546	            isTeleportPowerUp,
547	            allowNonMatchingSwap,
548	        };
549	    }
550	}
551	
552	export function trySwap(game, row1, col1, row2, col2) {
553	    if (!game.gameActive) return;
554	
555	    // Tutorial validation - only allow defined swaps during tutorial
556	    if (isTutorialActive(game)) {
557	        if (!isValidTutorialSwap(game, row1, col1, row2, col2)) {
558	            game.animateRevert(row1, col1, row2, col2);
559	            return false;
560	        }
561	    }
562	
563	    // Prevent swapping blocked/blocked-with-life tiles unless swap power-up on simple (non-rectangular) blocked
564	    const isSwapPowerUp = game.activePowerUp === "swap";
565	    const t1 = game.board[row1][col1];
566	    const t2 = game.board[row2][col2];
567	    const t1SimpleBlocked = isBlocked(t1) && !isRectangularBlocked(t1);
568	    const t2SimpleBlocked = isBlocked(t2) && !isRectangularBlocked(t2);
569	    if (isBlockedWithLife(t1) || isBlockedWithLife(t2)) return;
570	    if (isBlocked(t1) && !t1SimpleBlocked) return;
571	    if (isBlocked(t2) && !t2SimpleBlocked) return;
572	    if ((t1SimpleBlocked || t2SimpleBlocked) && !isSwapPowerUp) return;
573	
574	    const isAdjacentSwap = areAdjacent(row1, col1, row2, col2);
575	    const allowExtendedFreeSwap = !isAdjacentSwap && isExtendedFreeSwapAllowed(game, row1, col1, row2, col2);
576	    const allowTeleportSwap = !isAdjacentSwap && isTeleportSwapAllowed(game, row1, col1, row2, col2);
577	    const isPowerUpSwap = !isAdjacentSwap && game.activePowerUp === "teleport";
578	
579	    if (!isAdjacentSwap && !allowExtendedFreeSwap && !allowTeleportSwap && !isPowerUpSwap) {
580	        return false;
581	    }
582	
583	    // If animating, queue the swap to execute after animation completes
584	    if (game.animating) {
585	        game.interruptCascade = true;
586	        game.pendingSwap = {
587	            row1,
588	            col1,
589	            row2,
590	            col2,
591	            tile1: game.board[row1][col1],
592	            tile2: game.board[row2][col2],
593	        };
594	
595	        const gem1 = document.querySelector(`[data-row="${row1}"][data-col="${col1}"]`);
596	        const gem2 = document.querySelector(`[data-row="${row2}"][data-col="${col2}"]`);
597	        if (gem1) gem1.classList.add("pending-preview");
598	        if (gem2) gem2.classList.add("pending-preview");
599	
600	        return;
601	    }
602	
603	    // Execute board-level swap logic
604	    const result = executeSwap(game, row1, col1, row2, col2);
605	
606	    if (result.valid) {
607	        const { hasMatch, hasFreeSwap, hasTeleport, isSwapPowerUp, isTeleportPowerUp, allowNonMatchingSwap } = result;
608	
609	        game.updateMovesDisplay();
610	
611	        game.animateSwap(row1, col1, row2, col2, () => {
612	            game.renderBoard();
613	
614	            if (isTutorialActive(game)) {
615	                advanceTutorialStep(game);
616	            }
617	
618	            if (isSwapPowerUp) {
619	                game.consumePowerUp("swap");
620	                game.updatePowerUpButtons();
621	                track("power_up_used", {
622	                    level: game.currentLevel,
623	                    power_up_type: "swap",
624	                    remaining_moves: game.maxMoves - game.movesUsed,
625	                    uses_remaining: game.getTotalPowerUpCount("swap"),
626	                });
627	                game.deactivatePowerUp();
628	            }
629	
630	            if (isTeleportPowerUp) {
631	                game.consumePowerUp("teleport");
632	                game.updatePowerUpButtons();
633	                track("power_up_used", {
634	                    level: game.currentLevel,
635	                    power_up_type: "teleport",
636	                    remaining_moves: game.maxMoves - game.movesUsed,
637	                    uses_remaining: game.getTotalPowerUpCount("teleport"),
638	                });
639	                game.deactivatePowerUp();
640	            }
641	
642	            if (
643	                !hasMatch &&
644	                (allowNonMatchingSwap || hasTeleport || isTeleportPowerUp) &&
645	                !isSwapPowerUp &&
646	                !hasFreeSwap
647	            ) {
648	                game.lastSwapPosition = null;
649	                game.isUserSwap = false;
650	            }
651	
652	            document.querySelectorAll(".gem").forEach((gem) => {
653	                gem.classList.remove("dragging", "preview", "merge-preview", "unblock-preview");
654	            });
655	            game.selectedGem = null;
656	            game.isDragging = false;
657	            game.dragStartPos = null;
658	
659	            game.processMatches();
660	        });
661	
662	        return true;
663	    } else {
664	        game.animateRevert(row1, col1, row2, col2);
665	    }
